/**
 * thesis-router.mjs — Routes sector findings into relevant theses
 *
 * Builds a keyword index from thesis frontmatter (core_entities,
 * bullish_drivers, invalidation_triggers, etc.) then scores a block
 * of finding text against every thesis.
 *
 * Scoring:
 *   +1 per keyword/entity match
 *   -2 per invalidation trigger match (weighted heavier — breaks matter more)
 *
 * Only theses with |score| >= 2 are returned.
 */

import { readdirSync, readFileSync, writeFileSync, mkdirSync, existsSync } from 'fs';
import { join } from 'path';
import { getVaultRoot } from './config.mjs';
import { parseFrontmatter } from './history.mjs';
import { today } from './markdown.mjs';
import { buildNote } from './markdown.mjs';

// Minimum absolute score to surface a routing result
const SCORE_THRESHOLD = 2;

// Minimum unique term hits for an unmatched finding to become a stub
const STUB_HIT_THRESHOLD = 3;

/**
 * Load all conviction theses (excluding Baskets/) and build a routing index.
 * Returns a Map keyed by thesis name.
 * @returns {Map<string, ThesisEntry>}
 */
export function buildRoutingTable() {
  const thesesDir = join(getVaultRoot(), '10_Theses');
  const table = new Map();

  if (!existsSync(thesesDir)) return table;

  for (const file of readdirSync(thesesDir).filter(f => f.endsWith('.md'))) {
    const filePath = join(thesesDir, file);
    const fm = parseFrontmatter(readFileSync(filePath, 'utf-8'));
    if (!fm || fm.node_type !== 'thesis') continue;
    // Skip draft stubs to avoid circular routing
    if (fm.status === 'Draft') continue;

    const keywords = new Set();
    const bullish = new Set();
    const invalidation = new Set();

    function ingest(value, target) {
      const items = Array.isArray(value) ? value : (value ? [value] : []);
      for (const item of items) {
        // Strip wikilink markers and split into tokens
        const clean = String(item)
          .replace(/\[\[|\]\]/g, '')
          .replace(/[^a-zA-Z0-9\s-]/g, ' ');
        for (const token of clean.split(/\s+/).filter(t => t.length >= 2)) {
          target.add(token.toLowerCase());
          keywords.add(token.toLowerCase());
        }
      }
    }

    ingest(fm.core_entities, keywords);
    ingest(fm.name, keywords);
    ingest(fm.tags, keywords);
    ingest(fm.bullish_drivers, bullish);
    ingest(fm.bearish_drivers, keywords);
    ingest(fm.key_indicators, keywords);
    ingest(fm.invalidation_triggers, invalidation);

    const slug = file.replace(/\.md$/, '')
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-|-$/g, '');

    table.set(fm.name || file, {
      slug,
      file,
      filePath,
      name: fm.name || file,
      conviction: fm.conviction || 'low',
      allocationPriority: fm.allocation_priority || 'watch',
      keywords,
      bullish,
      invalidation,
    });
  }

  return table;
}

/**
 * Score a block of finding text against every thesis in the routing table.
 * @param {string} findingText — raw text from sector pulls (headlines, tickers, descriptions)
 * @param {Map} routingTable — from buildRoutingTable()
 * @returns {RoutingResult[]} sorted by |score| descending, threshold-filtered
 */
export function scoreFindings(findingText, routingTable) {
  const tokens = new Set(
    findingText
      .toLowerCase()
      .replace(/[^a-z0-9\s-]/g, ' ')
      .split(/\s+/)
      .filter(t => t.length >= 2)
  );

  const results = [];

  for (const [thesisName, entry] of routingTable) {
    let score = 0;
    const matched = new Set();
    const invalidationHits = [];

    for (const token of tokens) {
      if (entry.invalidation.has(token)) {
        score -= 2;
        invalidationHits.push(token);
        matched.add(token);
      } else if (entry.keywords.has(token)) {
        score += 1;
        matched.add(token);
      }
    }

    if (Math.abs(score) >= SCORE_THRESHOLD) {
      results.push(Object.freeze({
        thesisName,
        slug: entry.slug,
        file: entry.file,
        conviction: entry.conviction,
        allocationPriority: entry.allocationPriority,
        score,
        direction: score > 0 ? 'confirm' : 'contradict',
        matched: [...matched],
        invalidationHits,
      }));
    }
  }

  return results.sort((a, b) => Math.abs(b.score) - Math.abs(a.score));
}

/**
 * Determine if an unmatched finding is strong enough to warrant a new thesis stub.
 * @param {string} findingText
 * @param {Map} routingTable
 * @returns {boolean}
 */
export function shouldCreateStub(findingText, routingTable) {
  const allRouted = scoreFindings(findingText, routingTable);
  if (allRouted.length > 0) return false; // already matched an existing thesis

  const tokens = new Set(
    findingText.toLowerCase().replace(/[^a-z0-9\s]/g, ' ').split(/\s+/).filter(t => t.length >= 3)
  );
  return tokens.size >= STUB_HIT_THRESHOLD;
}

/**
 * Build a Draft thesis stub note for an unmatched sector pattern.
 * @param {string} sectorName — e.g. 'Tech Sector'
 * @param {string[]} matchedTerms — top keyword hits
 * @returns {{ slug: string, frontmatter: object, body: string }}
 */
export function buildThesisStub(sectorName, matchedTerms) {
  const t = today();
  const name = sectorName + ' — Emerging Pattern';
  const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
  const topTerms = [...new Set(matchedTerms)].slice(0, 5);

  const frontmatter = {
    node_type: 'thesis',
    name,
    status: 'Draft',
    conviction: 'low',
    timeframe: 'medium',
    allocation_priority: 'watch',
    allocation_rank: 99,
    why_now: 'Emerging pattern detected via sector scan — ' + sectorName,
    variant_perception: '',
    next_catalyst: '',
    disconfirming_evidence: 'None identified',
    expected_upside: '',
    expected_downside: '',
    position_sizing: 'watchlist only',
    core_entities: topTerms.map(t => '[[' + t + ']]'),
    bullish_drivers: topTerms.slice(0, 3).map(t => '[[' + t + ']]'),
    bearish_drivers: [],
    invalidation_triggers: [],
    supporting_regimes: [],
    key_indicators: [],
    required_sources: [],
    required_pull_families: [],
    monitor_status: 'on-track',
    monitor_last_review: t,
    monitor_change: 'Draft stub created by sector-scan.',
    break_risk_status: 'not-seen',
    monitor_action: 'Populate evidence and promote conviction before sizing.',
    tags: ['thesis', 'draft', 'sector-scan', sectorName.toLowerCase().replace(/\s+/g, '-')],
  };

  const body = [
    '## Investment Thesis',
    '',
    'Draft — populate from sector scan evidence before promoting to active.',
    '',
    '## Monitor Review',
    '',
    '- **Last review**: ' + t,
    '- **Change this week**: Draft stub from sector scan.',
    '- **Break risk status**: not-seen',
    '- **Action**: Populate evidence and promote conviction before sizing.',
    '',
  ].join('\n');

  return { slug, name, frontmatter, body };
}

/**
 * Write a CONFIRM or CONTRADICT signal note to 06_Signals/.
 * @param {RoutingResult} result
 * @param {string} sectorName
 * @param {string} signalsDir
 * @param {boolean} dryRun
 * @returns {string} file path written (or would-write path if dryRun)
 */
export function writeRoutingSignal(result, sectorName, signalsDir, dryRun = false) {
  const t = today();
  const prefix = result.direction === 'confirm' ? 'CONFIRM' : 'CONTRADICT';
  const upperSlug = result.slug.toUpperCase().replace(/-/g, '_');
  const fileName = t + '_' + prefix + '_' + upperSlug + '.md';
  const filePath = join(signalsDir, fileName);

  const severity = Math.abs(result.score) >= 4 ? 'alert' : 'watch';
  const suggestedAction = result.direction === 'confirm' ? 'compound' : 'reduce';

  const frontmatter = {
    signal_id: prefix + '_' + upperSlug,
    signal_name: prefix.charAt(0) + prefix.slice(1).toLowerCase() + ' — ' + result.thesisName,
    severity,
    date: t,
    sector: sectorName,
    thesis: '[[' + result.file.replace(/\.md$/, '') + ']]',
    score: result.score,
    direction: result.direction,
    matched_terms: result.matched,
    suggested_action: suggestedAction,
    tags: ['signal', 'sector-scan', result.direction, result.slug],
  };

  const evidenceLines = result.matched.map(m => '- `' + m + '`');
  const invalidLines = result.invalidationHits.length > 0
    ? ['', '**Invalidation triggers matched:**', ...result.invalidationHits.map(h => '- `' + h + '`')]
    : [];

  const actionLine = result.direction === 'confirm'
    ? 'Sector data supports this thesis. Consider increasing `conviction` or `allocation_priority` if supported by two independent sources.'
    : 'Sector data matches an invalidation trigger. Set `break_risk_status: "watch"` and review `disconfirming_evidence`.';

  const body = [
    '## ' + prefix.charAt(0) + prefix.slice(1).toLowerCase() + ' — ' + result.thesisName,
    '',
    '**Sector:** ' + sectorName + '  ',
    '**Score:** ' + result.score + '  ',
    '**Direction:** ' + result.direction,
    '',
    '## Evidence',
    '',
    ...evidenceLines,
    ...invalidLines,
    '',
    '## Suggested Action',
    '',
    actionLine,
    '',
    '## How to Apply',
    '',
    'Run `powershell scripts/update-thesis-scorecards.ps1` or edit `10_Theses/' + result.file + '` directly.',
    '',
  ].join('\n');

  const content = buildNote({ frontmatter, sections: [] });
  const fullContent = content + body;

  if (!dryRun) {
    if (!existsSync(signalsDir)) mkdirSync(signalsDir, { recursive: true });
    writeFileSync(filePath, fullContent, 'utf-8');
  }

  return filePath;
}

