/**
 * thesis-router.mjs — Routes sector findings into relevant theses
 *
 * Builds a keyword index from thesis frontmatter (core_entities,
 * bullish_drivers, invalidation_triggers, etc.) then scores a block
 * of finding text against every thesis.
 *
 * Scoring:
 *   +1 per keyword/entity match
 *   -2 per invalidation trigger match (weighted heavier — breaks matter more)
 *
 * Only theses with |score| >= 2 are returned.
 */

import { readdirSync, readFileSync, writeFileSync, mkdirSync, existsSync } from 'fs';
import { join } from 'path';
import { getVaultRoot } from './config.mjs';
import { parseFrontmatter } from './history.mjs';
import { today } from './markdown.mjs';
import { buildNote } from './markdown.mjs';

// Minimum absolute score to surface a routing result
const SCORE_THRESHOLD = 2;

// Minimum unique term hits for an unmatched finding to become a stub
const STUB_HIT_THRESHOLD = 3;

/**
 * Load all conviction theses (excluding Baskets/) and build a routing index.
 * Returns a Map keyed by thesis name.
 * @returns {Map<string, ThesisEntry>}
 */
export function buildRoutingTable() {
  const thesesDir = join(getVaultRoot(), '10_Theses');
  const table = new Map();

  if (!existsSync(thesesDir)) return table;

  for (const file of readdirSync(thesesDir).filter(f => f.endsWith('.md'))) {
    const filePath = join(thesesDir, file);
    const fm = parseFrontmatter(readFileSync(filePath, 'utf-8'));
    if (!fm || fm.node_type !== 'thesis') continue;
    // Skip draft stubs to avoid circular routing
    if (fm.status === 'Draft') continue;

    const keywords = new Set();
    const bullish = new Set();
    const invalidation = new Set();

    function ingest(value, target) {
      const items = Array.isArray(value) ? value : (value ? [value] : []);
      for (const item of items) {
        // Strip wikilink markers and split into tokens
        const clean = String(item)
          .replace(/\[\[|\]\]/g, '')
          .replace(/[^a-zA-Z0-9\s-]/g, ' ');
        for (const token of clean.split(/\s+/).filter(t => t.length >= 2)) {
          target.add(token.toLowerCase());
          keywords.add(token.toLowerCase());
        }
      }
    }

    ingest(fm.core_entities, keywords);
    ingest(fm.name, keywords);
    ingest(fm.tags, keywords);
    ingest(fm.bullish_drivers, bullish);
    ingest(fm.bearish_drivers, keywords);
    ingest(fm.key_indicators, keywords);
    ingest(fm.invalidation_triggers, invalidation);

    const slug = file.replace(/\.md$/, '')
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-|-$/g, '');

    table.set(fm.name || file, {
      slug,
      file,
      filePath,
      name: fm.name || file,
      conviction: fm.conviction || 'low',
      allocationPriority: fm.allocation_priority || 'watch',
      keywords,
      bullish,
      invalidation,
    });
  }

  return table;
}

/**
 * Score a block of finding text against every thesis in the routing table.
 * @param {string} findingText — raw text from sector pulls (headlines, tickers, descriptions)
 * @param {Map} routingTable — from buildRoutingTable()
 * @returns {RoutingResult[]} sorted by |score| descending, threshold-filtered
 */
export function scoreFindings(findingText, routingTable) {
  const tokens = new Set(
    findingText
      .toLowerCase()
      .replace(/[^a-z0-9\s-]/g, ' ')
      .split(/\s+/)
      .filter(t => t.length >= 2)
  );

  const results = [];

  for (const [thesisName, entry] of routingTable) {
    let score = 0;
    const matched = new Set();
    const invalidationHits = [];

    for (const token of tokens) {
      if (entry.invalidation.has(token)) {
        score -= 2;
        invalidationHits.push(token);
        matched.add(token);
      } else if (entry.keywords.has(token)) {
        score += 1;
        matched.add(token);
      }
    }

    if (Math.abs(score) >= SCORE_THRESHOLD) {
      results.push(Object.freeze({
        thesisName,
        slug: entry.slug,
        file: entry.file,
        conviction: entry.conviction,
        allocationPriority: entry.allocationPriority,
        score,
        direction: score > 0 ? 'confirm' : 'contradict',
        matched: [...matched],
        invalidationHits,
      }));
    }
  }

  return results.sort((a, b) => Math.abs(b.score) - Math.abs(a.score));
}

/**
 * Determine if an unmatched finding is strong enough to warrant a new thesis stub.
 * @param {string} findingText
 * @param {Map} routingTable
 * @returns {boolean}
 */
export function shouldCreateStub(findingText, routingTable) {
  const allRouted = scoreFindings(findingText, routingTable);
  if (allRouted.length > 0) return false; // already matched an existing thesis

  const tokens = new Set(
    findingText.toLowerCase().replace(/[^a-z0-9\s]/g, ' ').split(/\s+/).filter(t => t.length >= 3)
  );
  return tokens.size >= STUB_HIT_THRESHOLD;
}

/**
