 * @param {string} sectorName — e.g. 'Tech Sector'
 * @param {string[]} matchedTerms — top keyword hits
 * @returns {{ slug: string, frontmatter: object, body: string }}
 */
export function buildThesisStub(sectorName, matchedTerms) {
  const t = today();
