  const topTerms = [...new Set(matchedTerms)].slice(0, 5);

  const frontmatter = {
    node_type: 'thesis',
    name,
    status: 'Draft',
    conviction: 'low',
    timeframe: 'medium',
    allocation_priority: 'watch',
    allocation_rank: 99,
    why_now: 'Emerging pattern detected via sector scan — ' + sectorName,
    variant_perception: '',
    next_catalyst: '',
    disconfirming_evidence: 'None identified',
    expected_upside: '',
    expected_downside: '',
    position_sizing: 'watchlist only',
    core_entities: topTerms.map(t => '[[' + t + ']]'),
    bullish_drivers: topTerms.slice(0, 3).map(t => '[[' + t + ']]'),
    bearish_drivers: [],
    invalidation_triggers: [],
    supporting_regimes: [],
    key_indicators: [],
    required_sources: [],
    required_pull_families: [],
    monitor_status: 'on-track',
    monitor_last_review: t,
    monitor_change: 'Draft stub created by sector-scan.',
    break_risk_status: 'not-seen',
    monitor_action: 'Populate evidence and promote conviction before sizing.',
    tags: ['thesis', 'draft', 'sector-scan', sectorName.toLowerCase().replace(/\s+/g, '-')],
  };

  const body = [
    '## Investment Thesis',
    '',
    'Draft — populate from sector scan evidence before promoting to active.',
    '',
    '## Monitor Review',
    '',
    '- **Last review**: ' + t,
    '- **Change this week**: Draft stub from sector scan.',
    '- **Break risk status**: not-seen',
    '- **Action**: Populate evidence and promote conviction before sizing.',
    '',
  ].join('\n');

  return { slug, name, frontmatter, body };
}

/**
 * Write a CONFIRM or CONTRADICT signal note to 06_Signals/.
 * @param {RoutingResult} result
 * @param {string} sectorName
 * @param {string} signalsDir
 * @param {boolean} dryRun
 * @returns {string} file path written (or would-write path if dryRun)
 */
export function writeRoutingSignal(result, sectorName, signalsDir, dryRun = false) {
  const t = today();
  const prefix = result.direction === 'confirm' ? 'CONFIRM' : 'CONTRADICT';
  const upperSlug = result.slug.toUpperCase().replace(/-/g, '_');
  const fileName = t + '_' + prefix + '_' + upperSlug + '.md';
  const filePath = join(signalsDir, fileName);

  const severity = Math.abs(result.score) >= 4 ? 'alert' : 'watch';
  const suggestedAction = result.direction === 'confirm' ? 'compound' : 'reduce';

  const frontmatter = {
    signal_id: prefix + '_' + upperSlug,
    signal_name: prefix.charAt(0) + prefix.slice(1).toLowerCase() + ' — ' + result.thesisName,
    severity,
    date: t,
    sector: sectorName,
    thesis: '[[' + result.file.replace(/\.md$/, '') + ']]',
    score: result.score,
    direction: result.direction,
    matched_terms: result.matched,
    suggested_action: suggestedAction,
    tags: ['signal', 'sector-scan', result.direction, result.slug],
  };

  const evidenceLines = result.matched.map(m => '- `' + m + '`');
  const invalidLines = result.invalidationHits.length > 0
    ? ['', '**Invalidation triggers matched:**', ...result.invalidationHits.map(h => '- `' + h + '`')]
    : [];

  const actionLine = result.direction === 'confirm'
    ? 'Sector data supports this thesis. Consider increasing `conviction` or `allocation_priority` if supported by two independent sources.'
    : 'Sector data matches an invalidation trigger. Set `break_risk_status: "watch"` and review `disconfirming_evidence`.';

  const body = [
    '## ' + prefix.charAt(0) + prefix.slice(1).toLowerCase() + ' — ' + result.thesisName,
    '',
    '**Sector:** ' + sectorName + '  ',
    '**Score:** ' + result.score + '  ',
    '**Direction:** ' + result.direction,
    '',
