/**
 * sector-scan.mjs — Sector-to-thesis research pipeline
 *
 * For each sector basket, pulls SEC 8-Ks and news, then routes findings
 * through the thesis router. Outputs:
 *   - 05_Data_Pulls/Sectors/{date}_{Sector}.md    (one per sector)
 *   - 05_Data_Pulls/Sectors/{date}_Sector_Scan_Summary.md
 *   - 06_Signals/{date}_CONFIRM_{thesis}.md        (score >= +2)
 *   - 06_Signals/{date}_CONTRADICT_{thesis}.md     (score <= -2)
 *   - 10_Theses/{stub}.md                          (new patterns, no existing match)
 *
 * Flags:
 *   --sector <name>       Only scan this sector (slug or basket name prefix)
 *   --dry-run             Build routing table and print matches; no writes, no API calls
 *   --new-thesis-only     Only write new thesis stubs; skip confirm/contradict signals
 *   --no-fmp              Skip FMP calls
 */

import { readdirSync, readFileSync, writeFileSync, mkdirSync, existsSync } from 'fs';
import { join } from 'path';
import { getVaultRoot, getPullsDir, getSignalsDir } from '../lib/config.mjs';
import { today, buildNote, writeNote, dateStampedFilename } from '../lib/markdown.mjs';
import { listPullFiles } from '../lib/history.mjs';
import { SECTOR_MAP, findSector } from '../lib/sector-map.mjs';
import {
  buildRoutingTable,
  scoreFindings,
  shouldCreateStub,
  buildThesisStub,
  writeRoutingSignal,
} from '../lib/thesis-router.mjs';

// ─── Helpers ──────────────────────────────────────────────────────────────────

function log(msg) {
  console.log('[sector-scan] ' + msg);
}

/**
 * Find the most recently written pull files in a domain that match a pattern.
 * Uses today's date prefix to only consider files from this run.
 */
function findTodaysPulls(domain, pattern) {
  const t = today();
  return listPullFiles(domain)
    .filter(e => e.datePrefix === t && e.file.toLowerCase().includes(pattern.toLowerCase()))
    .slice(0, 3);
}

/**
 * Extract scoreable text from a pull note file.
 * Concatenates title, signals, and all markdown body text.
 */
function extractFindingsText(filePath) {
  if (!existsSync(filePath)) return '';
  const content = readFileSync(filePath, 'utf-8').replace(/\r\n/g, '\n');
  // Strip frontmatter
  const bodyMatch = content.match(/^---\n[\s\S]*?\n---\n([\s\S]*)$/);
  const body = bodyMatch ? bodyMatch[1] : content;
  // Keep ticker-like tokens and plain text; strip markdown syntax
  return body.replace(/[|#*`\[\]]/g, ' ').replace(/\s+/g, ' ').trim();
}

/**
 * Attempt to run a puller module. Returns true on success, false on failure.
 * Errors are logged but non-fatal.
 */
async function tryPull(modulePath, flags, label) {
  try {
    const mod = await import(modulePath);
    await mod.pull(flags);
    return true;
  } catch (err) {
    log('  WARN: ' + label + ' pull failed — ' + err.message);
    return false;
  }
}

// ─── Main export ──────────────────────────────────────────────────────────────

export async function pull(flags = {}) {
  const dryRun = Boolean(flags['dry-run']);
  const newThesisOnly = Boolean(flags['new-thesis-only']);
  const noFmp = Boolean(flags['no-fmp']);
  const sectorFilter = flags['sector'] ? String(flags['sector']) : null;

  const vaultRoot = getVaultRoot();
  const pullsDir = getPullsDir();
  const signalsDir = getSignalsDir();
  const sectorsDir = join(pullsDir, 'Sectors');
  const thesesDir = join(vaultRoot, '10_Theses');
  const t = today();

  // Determine which sectors to scan
  let sectors = SECTOR_MAP;
  if (sectorFilter) {
    const match = findSector(sectorFilter);
    if (!match) {
      throw new Error(
        'Unknown sector: "' + sectorFilter + '". ' +
        'Valid slugs: ' + SECTOR_MAP.map(s => s.slug).join(', ')
      );
    }
    sectors = [match];
  }

  // Build routing table from current vault state
  log('Building thesis routing table...');
  const routingTable = buildRoutingTable();
  log('  Loaded ' + routingTable.size + ' active theses');

  if (dryRun) {
    log('--- Routing table ---');
    for (const [name, entry] of routingTable) {
      log('  ' + name + ' (' + entry.keywords.size + ' keywords, ' + entry.invalidation.size + ' invalidation triggers)');
    }
    log('--- Sectors to scan ---');
    for (const s of sectors) {
      log('  ' + s.basket + ' → sec:' + s.secAlias + ' news:' + s.newsTopic);
    }
    log('[dry-run] No API calls or file writes.');
    return { dryRun: true, sectors: sectors.length, theses: routingTable.size };
  }

  // Ensure output directories exist
  if (!existsSync(sectorsDir)) mkdirSync(sectorsDir, { recursive: true });

  const summaryRows = [];
  const allSignalsWritten = [];
  const allStubsWritten = [];

  // ─── Per-sector scan loop ──────────────────────────────────────────────────
  for (const sector of sectors) {
    log('Scanning: ' + sector.basket);

    // Phase A: Pull SEC 8-Ks for this sector alias
    log('  SEC 8-Ks → --sectors ' + sector.secAlias);
    await tryPull('../pullers/sec.mjs', { sectors: sector.secAlias }, 'SEC/' + sector.secAlias);

    // Phase B: Pull news for this topic
    log('  NewsAPI → --topic ' + sector.newsTopic);
    await tryPull('../pullers/newsapi.mjs', { topic: sector.newsTopic, limit: 20 }, 'newsapi/' + sector.newsTopic);

    // Phase C: Optionally pull FMP equity screening
    if (!noFmp) {
      log('  FMP screening → --micro-small');
      await tryPull('../pullers/fmp.mjs', { 'micro-small': true }, 'FMP');
    }

    // Phase D: Collect findings text from today's pull notes
    const secPulls = findTodaysPulls('Government', sector.secAlias);
    const newsPulls = findTodaysPulls('Macro', sector.newsTopic)
      .concat(findTodaysPulls('Research', sector.newsTopic));

    const findingsText = [
      sector.basket,
      sector.secAlias,
      sector.newsTopic,
      ...secPulls.map(e => extractFindingsText(e.path)),
      ...newsPulls.map(e => extractFindingsText(e.path)),
    ].join(' ');

    // Phase E: Score against routing table
    const routingResults = scoreFindings(findingsText, routingTable);
    log('  Routing hits: ' + routingResults.length);

    // Phase F: Write signal notes
    const signalsWritten = [];
    if (!newThesisOnly) {
      for (const result of routingResults) {
        const sigPath = writeRoutingSignal(result, sector.basket, signalsDir, false);
        signalsWritten.push({ result, path: sigPath });
        allSignalsWritten.push(sigPath);
        log('  ' + result.direction.toUpperCase() + ' [score=' + result.score + '] → ' + result.thesisName);
      }
    }

    // Phase G: Check for new thesis stub candidate
    const createStub = shouldCreateStub(findingsText, routingTable);
    if (createStub) {
      const topTokens = findingsText
        .toLowerCase().replace(/[^a-z0-9\s]/g, ' ').split(/\s+/)
        .filter(t => t.length >= 4)
        .reduce((acc, t) => { acc[t] = (acc[t] || 0) + 1; return acc; }, {});
      const topTerms = Object.entries(topTokens)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 8)
        .map(([term]) => term);

      const stub = buildThesisStub(sector.basket.replace(' Sector Basket', ' Sector'), topTerms);
      const stubPath = join(thesesDir, stub.slug + '.md');

      if (!existsSync(stubPath)) {
        const stubContent = buildNote({ frontmatter: stub.frontmatter, sections: [] }) + stub.body;
        writeFileSync(stubPath, stubContent, 'utf-8');
        allStubsWritten.push(stubPath);
        log('  NEW THESIS STUB → ' + stub.name);
      }
    }

    // Phase H: Write per-sector pull note
    const sectorFrontmatter = {
      title: sector.basket + ' — ' + t,
      source: 'SEC EDGAR + NewsAPI',
      date_pulled: t,
      domain: 'sectors',
      data_type: 'sector_scan',
      frequency: 'on-demand',
      signal_status: routingResults.some(r => r.direction === 'contradict') ? 'alert'
        : routingResults.length > 0 ? 'watch' : 'clear',
      signals: routingResults.map(r => r.direction.toUpperCase() + ':' + r.thesisName),
      sector: sector.basket,
      sector_slug: sector.slug,
      thesis_hits: routingResults.length,
      confirms: routingResults.filter(r => r.direction === 'confirm').length,
      contradicts: routingResults.filter(r => r.direction === 'contradict').length,
      tags: ['sector', sector.slug, 'sector-scan'],
    };

    const routingSection = routingResults.length === 0
      ? 'No thesis routing hits above threshold.'
      : routingResults
          .map(r => '| ' + r.thesisName + ' | ' + (r.score > 0 ? '+' : '') + r.score + ' | ' + r.direction + ' | ' + r.matched.slice(0, 5).join(', ') + ' |')
          .join('\n');

    const sectorBody = [
      '## Routing Results',
      '',
      routingResults.length > 0
        ? '| Thesis | Score | Direction | Matched Terms |\n| --- | --- | --- | --- |\n' + routingSection
        : routingSection,
      '',
      '## Signals Written',
      '',
      signalsWritten.length === 0
        ? 'None.'
        : signalsWritten.map(s => '- [[' + s.path.split(/[\\/]/).pop().replace('.md', '') + ']]').join('\n'),
      '',
    ].join('\n');

    const sectorNote = buildNote({ frontmatter: sectorFrontmatter, sections: [] }) + sectorBody;
    const sectorFile = join(sectorsDir, dateStampedFilename(sector.basket.replace(' Sector Basket', '_Sector').replace(/\s+/g, '_')));
    writeFileSync(sectorFile, sectorNote, 'utf-8');

    summaryRows.push({
      basket: sector.basket,
      hits: routingResults.length,
      confirms: routingResults.filter(r => r.direction === 'confirm').length,
      contradicts: routingResults.filter(r => r.direction === 'contradict').length,
    });
  }

  // ─── Summary note ─────────────────────────────────────────────────────────
  const totalConfirms = summaryRows.reduce((n, r) => n + r.confirms, 0);
  const totalContradicts = summaryRows.reduce((n, r) => n + r.contradicts, 0);

  const summaryFrontmatter = {
    title: 'Sector Scan Summary — ' + t,
    source: 'sector-scan',
    date_pulled: t,
    domain: 'sectors',
    data_type: 'sector_scan',
    frequency: 'on-demand',
    signal_status: totalContradicts > 0 ? 'alert' : totalConfirms > 0 ? 'watch' : 'clear',
    signals: [],
    sectors_scanned: summaryRows.length,
    total_confirms: totalConfirms,
    total_contradicts: totalContradicts,
    new_thesis_stubs: allStubsWritten.length,
    tags: ['sector', 'sector-scan', 'summary'],
  };

  const summaryTableRows = summaryRows.map(
    r => '| ' + r.basket + ' | ' + r.confirms + ' | ' + r.contradicts + ' | ' + r.hits + ' |'
  ).join('\n');

  const summaryBody = [
    '## Sector Routing Summary',
    '',
    '| Sector | Confirms | Contradicts | Total Hits |',
    '| --- | --- | --- | --- |',
    summaryTableRows,
    '',
    '## Signals Written',
    '',
    allSignalsWritten.length === 0
      ? 'None.'
      : allSignalsWritten.map(p => '- [[' + p.split(/[\\/]/).pop().replace('.md', '') + ']]').join('\n'),
    '',
    '## New Thesis Stubs',
    '',
    allStubsWritten.length === 0
      ? 'None.'
      : allStubsWritten.map(p => '- [[' + p.split(/[\\/]/).pop().replace('.md', '') + ']]').join('\n'),
    '',
  ].join('\n');

  const summaryContent = buildNote({ frontmatter: summaryFrontmatter, sections: [] }) + summaryBody;
  const summaryFile = join(sectorsDir, dateStampedFilename('Sector_Scan_Summary'));
  writeFileSync(summaryFile, summaryContent, 'utf-8');

  log('Done. ' + summaryRows.length + ' sectors scanned. Confirms: ' + totalConfirms + ', Contradicts: ' + totalContradicts + ', Stubs: ' + allStubsWritten.length);

  return {
    sectors: summaryRows.length,
    confirms: totalConfirms,
    contradicts: totalContradicts,
    stubs: allStubsWritten.length,
    signalsWritten: allSignalsWritten,
    summaryFile,
  };
}
